package com.evolua.subscription.infrastructure.persistence; import jakarta.persistence.*; import java.time.Instant; @Entity @Table(name = "subscriptions") public class SubscriptionEntity { @Id @GeneratedValue(strategy = GenerationType.IDENTITY) private Long id; private String userId; private String planCode; private String status; private String billingCycle; private Boolean premium; private Instant createdAt; public Long getId() { return id; } public void setId(Long id) { this.id = id; } public String getUserId() { return userId; } public void setUserId(String userId) { this.userId = userId; } public String getPlanCode() { return planCode; } public void setPlanCode(String planCode) { this.planCode = planCode; } public String getStatus() { return status; } public void setStatus(String status) { this.status = status; } public String getBillingCycle() { return billingCycle; } public void setBillingCycle(String billingCycle) { this.billingCycle = billingCycle; } public Boolean getPremium() { return premium; } public void setPremium(Boolean premium) { this.premium = premium; } public Instant getCreatedAt() { return createdAt; } public void setCreatedAt(Instant createdAt) { this.createdAt = createdAt; } }
